const body = $input.first().json.body || $input.first().json;
const action = String(body.action || 'recall').toLowerCase();
const sessionId = String(body.session_id || '').trim();
const userId = String(body.user_id || 'local-user').trim();
const text = String(body.text || body.context || '').trim();
const approvalId = String(body.approval_id || '').trim();
const memoryWriteApproved = body.memory_write_approved === true;
const now = new Date();
const ttlKind = String(body.ttl_kind || 'working').toLowerCase();
const ttlHours = ttlKind === 'episodic' ? 24 * 30 : 4;
const expiresAt = new Date(now.getTime() + ttlHours * 60 * 60 * 1000).toISOString();

if (!sessionId) throw new Error('session_id is required');
if (!['recall', 'write', 'end'].includes(action)) throw new Error('action must be recall, write, or end');

const wantsWrite = action === 'write' || action === 'end';
const writeAllowed = wantsWrite && memoryWriteApproved && approvalId.length > 0;
const deniedReason = wantsWrite && !writeAllowed
  ? 'memory_write approval required; send memory_write_approved=true with approval_id'
  : null;

return {
  action,
  wants_write: wantsWrite,
  write_allowed: writeAllowed,
  denied_reason: deniedReason,
  session_id: sessionId,
  user_id: userId,
  text,
  query: String(body.query || text || sessionId).trim(),
  approval_id: approvalId,
  privacy_level: String(body.privacy_level || 'local_only'),
  ttl_kind: ttlKind,
  expires_at: expiresAt,
  created_at: now.toISOString(),
  route_id: String(body.route_id || 'general'),
  staff_mode: String(body.staff_mode || 'operator'),
  source: 'n8n-session-memory-bridge',
  collection: 'merlin_session',
  embedding_model: 'nomic-embed-text',
  expected_dimensions: 768
};

const request = $('Prepare Session Request').first().json;
const raw = $input.first().json || {};
const failed = Boolean(raw.error || raw.message?.includes?.('ECONNREFUSED'));
return {
  status: failed ? 'degraded' : 'stored',
  action: request.action,
  collection: 'merlin_session',
  session_id: request.session_id,
  memory_written: !failed,
  degraded: failed,
  warning: failed ? 'Qdrant or Ollama unavailable; session continued without memory write' : null,
  approval_id: request.approval_id,
  expires_at: request.expires_at
};

const request = $('Prepare Session Request').first().json;
if (request.denied_reason) {
  return {
    status: 'denied',
    action: request.action,
    collection: 'merlin_session',
    session_id: request.session_id,
    memory_written: false,
    degraded: false,
    warning: request.denied_reason,
    context_prefix: '',
    memories: []
  };
}

const raw = $input.first().json || {};
if (raw.error || !raw.result) {
  return {
    status: 'degraded',
    action: request.action,
    collection: 'merlin_session',
    session_id: request.session_id,
    memory_written: false,
    degraded: true,
    warning: 'Qdrant or Ollama unavailable; session continued without recall',
    context_prefix: '',
    memories: []
  };
}

const memories = (raw.result || []).map((item, index) => ({
  rank: index + 1,
  score: Math.round((item.score || 0) * 1000) / 1000,
  text: item.payload?.text || '',
  created_at: item.payload?.created_at || '',
  expires_at: item.payload?.expires_at || ''
}));
const contextPrefix = memories.map((m) => `[Session Memory ${m.rank} | score:${m.score}] ${m.text.substring(0, 500)}`).join('\n');
return {
  status: 'recalled',
  action: request.action,
  collection: 'merlin_session',
  session_id: request.session_id,
  memory_written: false,
  degraded: false,
  warning: null,
  context_prefix: contextPrefix,
  memories
};
